const { Web3 } = require('web3');
const { FlashbotsBundleProvider } = require('@flashbots/ethers-provider-bundle');
const { ethers } = require('ethers');

/**
 * Front-Running PROTECTION Bot
 * 
 * This tool helps users protect their transactions from being
 * front-run by MEV bots. It uses private mempools (Flashbots)
 * and other defensive strategies.
 */

class FrontRunningProtector {
    constructor(config) {
        this.rpcUrl = config.rpcUrl;
        this.flashbotsRelayUrl = config.flashbotsRelayUrl || 'https://relay.flashbots.net';
        this.web3 = new Web3(new Web3.providers.WebsocketProvider(config.wsUrl));
        this.provider = new ethers.JsonRpcProvider(config.rpcUrl);
        this.protectedWallet = new ethers.Wallet(config.privateKey, this.provider);
        this.flashbotsProvider = null;
        this.maxSlippageBps = config.maxSlippageBps || 50; // 0.5% default
    }

    async initialize() {
        // Connect to Flashbots relay for private transaction submission
        // Flashbots sends transactions directly to miners, bypassing the public mempool
        const authSigner = ethers.Wallet.createRandom();
        this.flashbotsProvider = await FlashbotsBundleProvider.create(
            this.provider,
            authSigner,
            this.flashbotsRelayUrl
        );
        console.log('[PROTECTOR] Connected to Flashbots relay for private tx submission');
    }

    /**
     * Submit a transaction privately via Flashbots to avoid the public mempool.
     * This is the #1 defense against front-running: don't broadcast publicly.
     */
    async submitPrivateTransaction(transaction) {
        if (!this.flashbotsProvider) {
            throw new Error('Flashbots provider not initialized. Call initialize() first.');
        }

        const blockNumber = await this.provider.getBlockNumber();
        const targetBlock = blockNumber + 1;

        console.log(`[PROTECTOR] Submitting private transaction for block ${targetBlock}`);

        const signedBundle = await this.flashbotsProvider.signBundle([
            {
                signer: this.protectedWallet,
                transaction: {
                    to: transaction.to,
                    data: transaction.data,
                    value: transaction.value || 0,
                    gasLimit: transaction.gasLimit || 300000,
                    maxFeePerGas: transaction.maxFeePerGas,
                    maxPriorityFeePerGas: transaction.maxPriorityFeePerGas,
                    chainId: 1,
                    type: 2,
                },
            },
        ]);

        // Simulate first to check for reverts
        const simulation = await this.flashbotsProvider.simulate(signedBundle, targetBlock);

        if (simulation.firstRevert) {
            console.error('[PROTECTOR] Transaction would revert:', simulation.firstRevert);
            return { success: false, error: 'Transaction would revert', simulation };
        }

        console.log('[PROTECTOR] Simulation successful. Submitting to Flashbots...');

        // Submit to multiple consecutive blocks for higher inclusion probability
        const submissions = [];
        for (let i = 0; i < 3; i++) {
            const submission = await this.flashbotsProvider.sendBundle(signedBundle, targetBlock + i);
            submissions.push(submission);
        }

        // Wait for inclusion
        const result = await submissions[0].wait();

        if (result === 0) {
            console.log('[PROTECTOR] Transaction included privately! No front-running possible.');
            return { success: true, blockNumber: targetBlock };
        } else if (result === 1) {
            console.log('[PROTECTOR] Bundle not included in target block, retrying...');
            return { success: false, error: 'Not included', retryable: true };
        } else {
            console.log('[PROTECTOR] Nonce too high, transaction may have been included');
            return { success: false, error: 'Nonce issue' };
        }
    }

    /**
     * Build a DEX swap transaction with front-running protection.
     * Uses tight slippage, deadline, and private submission.
     */
    async protectedSwap(swapParams) {
        const {
            routerAddress,
            routerAbi,
            amountIn,
            path,
            slippageBps,
            deadlineSeconds,
        } = swapParams;

        const router = new ethers.Contract(routerAddress, routerAbi, this.protectedWallet);

        // Get expected output
        const amountsOut = await router.getAmountsOut(amountIn, path);
        const expectedOutput = amountsOut[amountsOut.length - 1];

        // Apply tight slippage tolerance — this is a key defense
        const slippage = slippageBps || this.maxSlippageBps;
        const minOutput = (expectedOutput * BigInt(10000 - slippage)) / BigInt(10000);

        console.log(`[PROTECTOR] Expected output: ${ethers.formatEther(expectedOutput)}`);
        console.log(`[PROTECTOR] Minimum output (${slippage / 100}% slippage): ${ethers.formatEther(minOutput)}`);

        // Short deadline prevents delayed execution attacks
        const deadline = Math.floor(Date.now() / 1000) + (deadlineSeconds || 120);

        // Build the transaction
        const txData = router.interface.encodeFunctionData('swapExactTokensForTokens', [
            amountIn,
            minOutput,
            path,
            this.protectedWallet.address,
            deadline,
        ]);

        // Get current gas prices
        const feeData = await this.provider.getFeeData();

        const transaction = {
            to: routerAddress,
            data: txData,
            value: 0,
            gasLimit: 300000,
            maxFeePerGas: feeData.maxFeePerGas,
            maxPriorityFeePerGas: feeData.maxPriorityFeePerGas,
        };

        // Submit privately via Flashbots
        return await this.submitPrivateTransaction(transaction);
    }

    /**
     * Monitor the public mempool for suspicious activity targeting our address.
     * Alerts if someone appears to be targeting our pending transactions.
     */
    async monitorForThreats(watchAddresses, callback) {
        console.log('[PROTECTOR] Monitoring mempool for threats against protected addresses...');

        const subscription = await this.web3.eth.subscribe('pendingTransactions');

        subscription.on('data', async (txHash) => {
            try {
                const tx = await this.web3.eth.getTransaction(txHash);
                if (!tx || !tx.to) return;

                const threat = this.analyzeThreat(tx, watchAddresses);
                if (threat.isThreat) {
                    console.warn(`[PROTECTOR] ⚠️  Potential front-run detected!`);
                    console.warn(`  TX Hash: ${txHash}`);
                    console.warn(`  From: ${tx.from}`);
                    console.warn(`  Threat type: ${threat.type}`);
                    console.warn(`  Gas price: ${this.web3.utils.fromWei(tx.gasPrice || '0', 'gwei')} gwei`);

                    if (callback) {
                        callback(threat);
                    }
                }
            } catch (err) {
                // Transaction may have been mined already
            }
        });

        return subscription;
    }

    /**
     * Analyze a pending transaction for front-running indicators.
     */
    analyzeThreat(tx, watchAddresses) {
        const normalizedWatch = watchAddresses.map((a) => a.toLowerCase());
        const txTo = tx.to?.toLowerCase();
        const txInput = tx.input || tx.data || '0x';

        // Known DEX router method signatures
        const swapSignatures = [
            '0x38ed1739', // swapExactTokensForTokens
            '0x8803dbee', // swapTokensForExactTokens
            '0x7ff36ab5', // swapExactETHForTokens
            '0x18cbafe5', // swapExactTokensForETH
            '0x5c11d795', // swapExactTokensForTokensSupportingFeeOnTransferTokens
            '0xfb3bdb41', // swapETHForExactTokens
            '0x04e45aaf', // Uniswap V3 exactInputSingle
            '0xb858183f', // Uniswap V3 exactInput
        ];

        const methodSig = txInput.slice(0, 10);
        const isSwap = swapSignatures.includes(methodSig);

        // Check if the transaction interacts with the same contracts we're watching
        const targetsWatchedContract = normalizedWatch.includes(txTo);

        // Check for abnormally high gas price (front-running indicator)
        const gasPriceGwei = parseFloat(this.web3.utils.fromWei(tx.gasPrice || '0', 'gwei'));
        const isHighGas = gasPriceGwei > 100; // Configurable threshold

        // Check for known MEV bot patterns
        const isMevBot = this.isKnownMevPattern(tx);

        const isThreat = (targetsWatchedContract && isSwap && isHighGas) || isMevBot;

        return {
            isThreat,
            type: isMevBot
                ? 'known_mev_bot'
                : isHighGas
                    ? 'high_gas_swap'
                    : 'suspicious_interaction',
            txHash: tx.hash,
            from: tx.from,
            to: tx.to,
            gasPrice: gasPriceGwei,
            methodSignature: methodSig,
            isSwap,
        };
    }

    /**
     * Detect known MEV bot patterns.
     */
    isKnownMevPattern(tx) {
        const input = tx.input || tx.data || '0x';

        // Sandwich attack pattern: very short input with high gas
        // (bots often use custom contracts with minimal calldata)
        if (input.length < 20 && parseFloat(this.web3.utils.fromWei(tx.gasPrice || '0', 'gwei')) > 200) {
            return true;
        }

        // Flashbots-style bundle transactions often have specific patterns
        // (This is a simplified heuristic)
        if (tx.to === tx.from) {
            return true; // Self-calls are often MEV bot setup transactions
        }

        return false;
    }

    /**
     * Split a large swap into smaller chunks to reduce front-running profitability.
     * This makes it economically unattractive for bots to sandwich the trade.
     */
    async splitSwap(swapParams, numberOfChunks = 4) {
        const { amountIn, ...rest } = swapParams;
        const chunkSize = BigInt(amountIn) / BigInt(numberOfChunks);
        const results = [];

        console.log(`[PROTECTOR] Splitting swap into ${numberOfChunks} chunks of ${ethers.formatEther(chunkSize)} each`);

        for (let i = 0; i < numberOfChunks; i++) {
            const isLastChunk = i === numberOfChunks - 1;
            // Last chunk gets any remainder
            const thisChunkSize = isLastChunk
                ? BigInt(amountIn) - chunkSize * BigInt(numberOfChunks - 1)
                : chunkSize;

            console.log(`[PROTECTOR] Submitting chunk ${i + 1}/${numberOfChunks}...`);

            const result = await this.protectedSwap({
                ...rest,
                amountIn: thisChunkSize,
            });

            results.push(result);

            // Random delay between chunks to avoid pattern detection
            if (!isLastChunk) {
                const delay = Math.floor(Math.random() * 5000) + 2000;
                console.log(`[PROTECTOR] Waiting ${delay}ms before next chunk...`);
                await new Promise((resolve) => setTimeout(resolve, delay));
            }
        }

        return results;
    }

    /**
     * Use a commit-reveal scheme for additional protection.
     * Phase 1: Submit a commitment hash (reveals nothing about the trade).
     * Phase 2: Reveal and execute the actual trade.
     */
    async commitRevealSwap(commitRevealContract, swapParams) {
        const { routerAddress, amountIn, path, slippageBps } = swapParams;

        // Phase 1: Commit
        const secret = ethers.randomBytes(32);
        const commitment = ethers.keccak256(
            ethers.AbiCoder.defaultAbiCoder().encode(
                ['address', 'uint256', 'address[]', 'bytes32'],
                [routerAddress, amountIn, path, secret]
            )
        );

        console.log('[PROTECTOR] Phase 1: Submitting commitment...');
        const commitTx = {
            to: commitRevealContract,
            data: new ethers.Interface([
                'function commit(bytes32 commitment)',
            ]).encodeFunctionData('commit', [commitment]),
            gasLimit: 100000,
            maxFeePerGas: (await this.provider.getFeeData()).maxFeePerGas,
            maxPriorityFeePerGas: (await this.provider.getFeeData()).maxPriorityFeePerGas,
        };

        await this.submitPrivateTransaction(commitTx);

        // Wait for commitment to be mined and confirmed
        console.log('[PROTECTOR] Waiting for commitment confirmation...');
        await new Promise((resolve) => setTimeout(resolve, 15000));

        // Phase 2: Reveal and execute
        console.log('[PROTECTOR] Phase 2: Revealing and executing swap...');
        const revealTx = {
            to: commitRevealContract,
            data: new ethers.Interface([
                'function revealAndExecute(address router, uint256 amountIn, address[] path, uint256 slippageBps, bytes32 secret)',
            ]).encodeFunctionData('revealAndExecute', [
                routerAddress,
                amountIn,
                path,
                slippageBps || this.maxSlippageBps,
                secret,
            ]),
            gasLimit: 500000,
            maxFeePerGas: (await this.provider.getFeeData()).maxFeePerGas,
            maxPriorityFeePerGas: (await this.provider.getFeeData()).maxPriorityFeePerGas,
        };

        return await this.submitPrivateTransaction(revealTx);
    }

    /**
     * Generate a report of MEV activity on recent blocks.
     */
    async generateMevReport(blockCount = 10) {
        const currentBlock = await this.provider.getBlockNumber();
        const report = {
            blocksAnalyzed: blockCount,
            startBlock: currentBlock - blockCount + 1,
            endBlock: currentBlock,
            suspiciousTxCount: 0,
            sandwichAttacks: [],
            frontRuns: [],
        };

        console.log(`[PROTECTOR] Analyzing blocks ${report.startBlock} to ${report.endBlock}...`);

        for (let i = report.startBlock; i <= report.endBlock; i++) {
            const block = await this.provider.getBlock(i, true);
            if (!block || !block.transactions) continue;

            // Look for sandwich patterns: buy → victim → sell from same address
            const txsByAddress = {};
            for (const tx of block.transactions) {
                const from = typeof tx === 'string' ? null : tx.from?.toLowerCase();
                if (!from) continue;
                if (!txsByAddress[from]) txsByAddress[from] = [];
                txsByAddress[from].push(tx);
            }

            for (const [address, txs] of Object.entries(txsByAddress)) {
                if (txs.length >= 2) {
                    // Simplified sandwich detection: same sender, 2+ swaps in same block
                    const swapTxs = txs.filter((tx) => {
                        const input = tx.data || '0x';
                        const sig = input.slice(0, 10);
                        return [
                            '0x38ed1739',
                            '0x7ff36ab5',
                            '0x18cbafe5',
                            '0x04e45aaf',
                        ].includes(sig);
                    });

                    if (swapTxs.length >= 2) {
                        report.sandwichAttacks.push({
                            block: i,
                            attacker: address,
                            transactionCount: swapTxs.length,
                            txHashes: swapTxs.map((tx) => tx.hash),
                        });
                        report.suspiciousTxCount += swapTxs.length;
                    }
                }
            }
        }

        console.log(`[PROTECTOR] Report complete.`);
        console.log(`  Suspicious transactions: ${report.suspiciousTxCount}`);
        console.log(`  Potential sandwich attacks: ${report.sandwichAttacks.length}`);

        return report;
    }

    async shutdown() {
        console.log('[PROTECTOR] Shutting down...');
        if (this.web3.currentProvider?.disconnect) {
            this.web3.currentProvider.disconnect();
        }
    }
}

